// Dev Pulse Dashboard
// Fetches live engineering news from data/news.json (generated by GitHub Actions)

let allNews = [];
let activeFilter = 'all';

async function fetchLiveData() {
  const cacheBust = `?t=${Date.now()}`;
  try {
    const res = await fetch(`data/news.json${cacheBust}`, { cache: 'no-store' });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    allNews = await res.json();
    console.log(`✅ Loaded ${allNews.length} articles`);
    return true;
  } catch (err) {
    console.error('❌ Failed to load news:', err);
    return false;
  }
}

function getCategoryLabel(category) {
  const labels = {
    'ai-coding': 'AI Coding',
    'testing': 'Testing & QA',
    'microservices': 'Microservices',
    'fintech': 'Fintech',
    'devprod': 'Dev Productivity',
    'security': 'Security'
  };
  return labels[category] || category;
}

function formatDate(timestamp) {
  if (!timestamp) return '';
  const date = new Date(timestamp);
  const now = new Date();
  const diffMs = now - date;
  const diffMins = Math.floor(diffMs / 60000);
  const diffHours = Math.floor(diffMs / 3600000);
  const diffDays = Math.floor(diffMs / 86400000);

  if (diffMins < 1) return 'just now';
  if (diffMins < 60) return `${diffMins}m ago`;
  if (diffHours < 24) return `${diffHours}h ago`;
  if (diffDays < 7) return `${diffDays}d ago`;
  return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
}

function renderNews(filter = 'all') {
  const container = document.getElementById('newsGrid');
  const emptyState = document.getElementById('emptyState');

  const filtered = filter === 'all' ? allNews : allNews.filter(n => n.category === filter);

  if (filtered.length === 0) {
    container.innerHTML = '';
    emptyState.classList.remove('hidden');
    return;
  }

  emptyState.classList.add('hidden');
  container.innerHTML = '';

  filtered.forEach((item, idx) => {
    const card = document.createElement('article');
    card.className = 'news-card';
    card.style.animation = `fadeInUp 0.4s ease ${idx * 0.04}s backwards`;

    const imageHtml = item.image
      ? `<div class="news-image"><img src="${escapeHtml(item.image)}" alt="" loading="lazy" onerror="this.parentElement.innerHTML='<div class=\\'news-image-placeholder\\'>📰</div>'"></div>`
      : `<div class="news-image"><div class="news-image-placeholder">${getCategoryEmoji(item.category)}</div></div>`;

    card.innerHTML = `
      ${imageHtml}
      <div class="news-body">
        <div class="news-meta">
          <span class="news-tag ${escapeHtml(item.category || '')}">${escapeHtml(getCategoryLabel(item.category))}</span>
          <span class="news-source">${escapeHtml(item.source || 'Unknown')}</span>
        </div>
        <h3 class="news-title">
          <a href="${escapeHtml(item.url || '#')}" target="_blank" rel="noopener noreferrer">
            ${escapeHtml(item.title || 'Untitled')}
          </a>
        </h3>
        <p class="news-excerpt">${escapeHtml(item.excerpt || '')}</p>
        <div class="news-footer">
          <span class="news-date">${escapeHtml(formatDate(item.timestamp))}</span>
          <a href="${escapeHtml(item.url || '#')}" target="_blank" rel="noopener noreferrer" class="news-read-more">
            Read more →
          </a>
        </div>
      </div>
    `;

    container.appendChild(card);
  });

  console.log(`📰 Rendered ${filtered.length} articles for filter: ${filter}`);
}

function getCategoryEmoji(category) {
  const emojis = {
    'ai-coding': '🤖',
    'testing': '🧪',
    'microservices': '🌐',
    'fintech': '💳',
    'devprod': '🚀',
    'security': '🔒'
  };
  return emojis[category] || '📰';
}

function escapeHtml(str) {
  if (str === null || str === undefined) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function updateStats() {
  document.getElementById('totalArticles').textContent = allNews.length;
  const sources = new Set(allNews.map(n => n.source).filter(Boolean));
  document.getElementById('totalSources').textContent = sources.size;
}

function updateLastUpdateTime() {
  const now = new Date();
  document.getElementById('lastUpdate').textContent =
    `Updated ${now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' })}`;
}

async function refreshData() {
  const btn = document.querySelector('.refresh-btn');
  btn.classList.add('loading');

  const success = await fetchLiveData();
  if (success) {
    renderNews(activeFilter);
    updateStats();
    updateLastUpdateTime();
  }

  setTimeout(() => btn.classList.remove('loading'), 500);
}

// Filter chip handlers
document.querySelectorAll('.chip').forEach(chip => {
  chip.addEventListener('click', () => {
    document.querySelectorAll('.chip').forEach(c => c.classList.remove('active'));
    chip.classList.add('active');
    activeFilter = chip.dataset.category;
    renderNews(activeFilter);
  });
});

// Initialize
document.addEventListener('DOMContentLoaded', async () => {
  console.log('🚀 Dev Pulse initializing...');

  await fetchLiveData();
  renderNews();
  updateStats();
  updateLastUpdateTime();

  // Auto-refresh every 5 minutes
  setInterval(async () => {
    console.log('🔄 Auto-refresh');
    await fetchLiveData();
    renderNews(activeFilter);
    updateStats();
    updateLastUpdateTime();
  }, 300000);
});

// Inject card animation styles
const style = document.createElement('style');
style.textContent = `
  @keyframes fadeInUp {
    from {
      opacity: 0;
      transform: translateY(12px);
    }
    to {
      opacity: 1;
      transform: translateY(0);
    }
  }
`;
document.head.appendChild(style);
